/// Pearson correlation of (close_t, close_{t-1}) over the last `period`
/// bars — a lag-1 autocorrelation for single-symbol momentum / mean-
/// reversion classification. `ρ → +1` is strong momentum,
/// `ρ → 0` is a random walk, `ρ → −1` is strong mean reversion.
pub fn compute_correl_snapshot(
    symbol: &str,
    as_of: &str,
    bars: &[HistoricalPriceRow],
) -> CorrelSnapshot {
    let sym = symbol.to_uppercase();
    let mut sorted: Vec<&HistoricalPriceRow> = bars.iter().collect();
    sorted.sort_by(|a, b| a.date.cmp(&b.date));
    let n = sorted.len();
    let period = 30usize;
    let min_bars = period + 2;
    if n < min_bars {
        return CorrelSnapshot {
            symbol: sym,
            as_of: as_of.into(),
            period,
            correl_label: "INSUFFICIENT_DATA".into(),
            note: format!("need ≥{} bars, got {}", min_bars, n),
            ..Default::default()
        };
    }
    let correl_at = |end_idx: usize| -> (f64, f64, f64, f64, f64) {
        let start = end_idx + 1 - period;
        let xs: Vec<f64> = (start..=end_idx).map(|i| sorted[i].close).collect();
        let ys: Vec<f64> = (start..=end_idx).map(|i| sorted[i - 1].close).collect();
        let mx: f64 = xs.iter().sum::<f64>() / period as f64;
        let my: f64 = ys.iter().sum::<f64>() / period as f64;
        let mut sxx = 0.0f64;
        let mut syy = 0.0f64;
        let mut sxy = 0.0f64;
        for i in 0..period {
            let dx = xs[i] - mx;
            let dy = ys[i] - my;
            sxx += dx * dx;
            syy += dy * dy;
            sxy += dx * dy;
        }
        let sdx = (sxx / period as f64).sqrt();
        let sdy = (syy / period as f64).sqrt();
        let rho = if sxx > 0.0 && syy > 0.0 {
            sxy / (sxx.sqrt() * syy.sqrt())
        } else {
            0.0
        };
        (rho, mx, my, sdx, sdy)
    };
    let (rho_now, mx, my, sdx, sdy) = correl_at(n - 1);
    let (rho_prev, _, _, _, _) = correl_at(n - 2);
    let label = if rho_now >= 0.7 {
        "STRONG_MOMO"
    } else if rho_now >= 0.2 {
        "MOMO"
    } else if rho_now <= -0.7 {
        "STRONG_MEAN_REVERT"
    } else if rho_now <= -0.2 {
        "MEAN_REVERT"
    } else {
        "RANDOM_WALK"
    };
    CorrelSnapshot {
        symbol: sym,
        as_of: as_of.into(),
        bars_used: n,
        period,
        correl: rho_now,
        correl_prev: rho_prev,
        mean_x: mx,
        mean_y: my,
        stddev_x: sdx,
        stddev_y: sdy,
        last_close: sorted[n - 1].close,
        correl_label: label.into(),
        note: String::new(),
    }
}

// ── Round 69 compute fns ────────────────────────────────────────────

/// Walk the trailing `period`-bar window ending at `end_idx` and return
/// `(min_val, min_idx_in_series, max_val, max_idx_in_series)`. The two
/// indices are absolute positions in the sorted array (so `end_idx -
/// idx_in_series` gives a "bars ago" recency).
fn window_extrema(
    sorted: &[&HistoricalPriceRow],
    end_idx: usize,
    period: usize,
) -> (f64, usize, f64, usize) {
    let start = end_idx + 1 - period;
    let mut min_val = sorted[start].close;
    let mut max_val = sorted[start].close;
    let mut min_idx = start;
    let mut max_idx = start;
    for i in (start + 1)..=end_idx {
        let c = sorted[i].close;
        if c < min_val {
            min_val = c;
            min_idx = i;
        }
        if c > max_val {
            max_val = c;
            max_idx = i;
        }
    }
    (min_val, min_idx, max_val, max_idx)
}

fn position_label(pct: f64, high_is_positive: bool) -> &'static str {
    // Three-band cutoff (25% / 75%) — labels depend on whether the
    // caller is framing MIN (near low = bad / bullish-setup) or MAX
    // (near high = good / breakout-setup). Same cutoffs either way,
    // naming reversed.
    if high_is_positive {
        if pct >= 75.0 {
            "NEAR_HIGH"
        } else if pct <= 25.0 {
            "NEAR_LOW"
        } else {
            "MID"
        }
    } else {
        if pct <= 25.0 {
            "NEAR_LOW"
        } else if pct >= 75.0 {
            "NEAR_HIGH"
        } else {
            "MID"
        }
    }
}

fn recency_label(bars_ago: usize, period: usize, is_high: bool) -> &'static str {
    let frac = bars_ago as f64 / period as f64;
    if is_high {
        if frac <= 0.1 {
            "FRESH_HIGH"
        } else if frac <= 0.33 {
            "RECENT_HIGH"
        } else if frac <= 0.66 {
            "OLD_HIGH"
        } else {
            "STALE_HIGH"
        }
    } else {
        if frac <= 0.1 {
            "FRESH_LOW"
        } else if frac <= 0.33 {
            "RECENT_LOW"
        } else if frac <= 0.66 {
            "OLD_LOW"
        } else {
            "STALE_LOW"
        }
    }
}

pub fn compute_min_snapshot(symbol: &str, as_of: &str, bars: &[HistoricalPriceRow]) -> MinSnapshot {
    let sym = symbol.to_uppercase();
    let mut sorted: Vec<&HistoricalPriceRow> = bars.iter().collect();
    sorted.sort_by(|a, b| a.date.cmp(&b.date));
    let n = sorted.len();
    let period = 30usize;
    let min_bars = period + 1;
    if n < min_bars {
        return MinSnapshot {
            symbol: sym,
            as_of: as_of.into(),
            period,
            min_label: "INSUFFICIENT_DATA".into(),
            note: format!("need ≥{} bars, got {}", min_bars, n),
            ..Default::default()
        };
    }
    let (min_now, _, max_now, _) = window_extrema(&sorted, n - 1, period);
    let (min_prev, _, _, _) = window_extrema(&sorted, n - 2, period);
    let close = sorted[n - 1].close;
    let range = max_now - min_now;
    let pct = if range.abs() > 1e-12 {
        (close - min_now) / range * 100.0
    } else {
        50.0
    };
    MinSnapshot {
        symbol: sym,
        as_of: as_of.into(),
        bars_used: n,
        period,
        min_val: min_now,
        min_prev,
        max_ref: max_now,
        last_close: close,
        position_pct: pct,
        min_label: position_label(pct, true).into(),
        note: String::new(),
    }
}

